 1→export { useProjects, useProject } from './useProjects';
 2→export { useSessions, useSession, useSessionMutation, useDeleteSession, useDeletedSessionCount } from './useSessions';
 3→export { useInsights, useDeleteInsight } from './useInsights';
 4→export { useMessages } from './useMessages';
 5→export { useDashboardStats } from './useAnalytics';
 6→export { useAnalyzeSession } from './useAnalysis';
 7→export { useLlmConfig, useSaveLlmConfig } from './useConfig';
 8→export { useExportMarkdown } from './useExport';
 9→export { useFacetAggregation, useReflectSnapshot } from './useReflect';
10→export { useMissingFacets, useBackfillFacets } from './useFacets';
11→

  1→import { useState, useCallback, useRef, useEffect } from 'react';
  2→import { useQueryClient } from '@tanstack/react-query';
  3→import { useProjects } from '@/hooks/useProjects';
  4→import { useFacetAggregation, useReflectSnapshot } from '@/hooks/useReflect';
  5→import { reflectGenerateStream } from '@/lib/api';
  6→import { parseSSEStream } from '@/lib/sse';
  7→import { Card, CardContent, CardHeader, CardTitle, CardDescription } from '@/components/ui/card';
  8→import { Button } from '@/components/ui/button';
  9→import { Badge } from '@/components/ui/badge';
 10→import { Skeleton } from '@/components/ui/skeleton';
 11→import { Tabs, TabsList, TabsTrigger, TabsContent } from '@/components/ui/tabs';
 12→import { ErrorCard } from '@/components/ErrorCard';
 13→import { WorkingStyleHeroCard } from '@/components/patterns/WorkingStyleHeroCard';
 14→import { useThemeColors } from '@/lib/hooks/useThemeColors';
 15→import { CHART_COLORS } from '@/lib/constants/colors';
 16→import {
 17→  BarChart, Bar, XAxis, YAxis, CartesianGrid, Tooltip, ResponsiveContainer,
 18→  PieChart, Pie, Cell, Legend,
 19→} from 'recharts';
 20→import {
 21→  AlertTriangle, Sparkles, Shield, Brain, Copy, Check, Loader2, Zap,
 22→} from 'lucide-react';
 23→
 24→// CHART_COLORS.models is the shared hex color array for multi-series charts
 25→const PALETTE = CHART_COLORS.models;
 26→
 27→// Friction bar severity color based on avg_severity (1=low, 2=medium, 3=high)
 28→function frictionBarColor(avgSeverity: number): string {
 29→  if (avgSeverity >= 2.5) return '#ef4444'; // red-500 (high)
 30→  if (avgSeverity >= 2.0) return '#f97316'; // orange-500
 31→  if (avgSeverity >= 1.5) return '#f59e0b'; // amber-500
 32→  return '#22c55e'; // green-500 (low)
 33→}
 34→
 35→function formatRelativeDate(iso: string): string {
 36→  const diff = Date.now() - new Date(iso).getTime();
 37→  const mins = Math.max(0, Math.floor(diff / 60000));
 38→  if (mins < 1) return 'just now';
 39→  if (mins < 60) return `${mins}m ago`;
 40→  const hours = Math.floor(mins / 60);
 41→  if (hours < 24) return `${hours}h ago`;
 42→  const days = Math.floor(hours / 24);
 43→  return `${days}d ago`;
 44→}
 45→
 46→function formatShortDate(iso: string): string {
 47→  return new Date(iso).toLocaleDateString('en-US', { month: 'short', day: 'numeric' });
 48→}
 49→
 50→type PatternsRange = '7d' | '30d' | '90d' | 'all';
 51→
 52→const rangeOptions: { value: PatternsRange; label: string }[] = [
 53→  { value: '7d', label: '7d' },
 54→  { value: '30d', label: '30d' },
 55→  { value: '90d', label: '90d' },
 56→  { value: 'all', label: 'All' },
 57→];
 58→
 59→export default function PatternsPage() {
 60→  const [range, setRange] = useState<PatternsRange>('30d');
 61→  const [selectedProject, setSelectedProject] = useState<string | undefined>(undefined);
 62→  const [generating, setGenerating] = useState(false);
 63→  const [generationProgress, setGenerationProgress] = useState('');
 64→  const [reflectResults, setReflectResults] = useState<Record<string, unknown> | null>(null);
 65→  const [copiedKey, setCopiedKey] = useState<string | null>(null);
 66→  const { tooltipBg, tooltipBorder } = useThemeColors();
 67→  const abortRef = useRef<AbortController | null>(null);
 68→  const queryClient = useQueryClient();
 69→
 70→  const { data: projects = [] } = useProjects();
 71→
 72→  const { data: snapshotData } = useReflectSnapshot({
 73→    period: range,
 74→    project: selectedProject,
 75→  });
 76→
 77→  const { data: aggregation, isLoading, isError, refetch } = useFacetAggregation({
 78→    period: range,
 79→    project: selectedProject,
 80→  });
 81→
 82→  // Abort in-flight generation on unmount
 83→  useEffect(() => {
 84→    return () => {
 85→      abortRef.current?.abort();
 86→    };
 87→  }, []);
 88→
 89→  // Auto-load cached snapshot when it arrives and no local results exist yet
 90→  useEffect(() => {
 91→    if (snapshotData?.snapshot?.results && !reflectResults && !generating) {
 92→      setReflectResults(snapshotData.snapshot.results);
 93→    }
 94→  }, [snapshotData, reflectResults, generating]);
 95→
 96→  const handleRangeChange = useCallback((newRange: PatternsRange) => {
 97→    setRange(newRange);
 98→    setReflectResults(null);
 99→  }, []);
100→
101→  const handleProjectChange = useCallback((projectId: string | undefined) => {
102→    setSelectedProject(projectId);
103→    setReflectResults(null);
104→  }, []);
105→
106→  const handleGenerate = useCallback(async () => {
107→    abortRef.current?.abort();
108→    const controller = new AbortController();
109→    abortRef.current = controller;
110→
111→    setGenerating(true);
112→    setGenerationProgress('Starting...');
113→    setReflectResults(null);
114→
115→    try {
116→      const response = await reflectGenerateStream(
117→        { period: range, project: selectedProject },
118→        controller.signal
119→      );
120→
121→      if (!response.body) throw new Error('No response body');
122→
123→      for await (const event of parseSSEStream(response.body)) {
124→        if (event.event === 'progress') {
125→          try {
126→            const data = JSON.parse(event.data) as { message?: string };
127→            setGenerationProgress(data.message || 'Processing...');
128→          } catch { /* skip malformed event */ }
129→        } else if (event.event === 'complete') {
130→          try {
131→            const data = JSON.parse(event.data) as { results?: Record<string, unknown> };
132→            setReflectResults(data.results ?? null);
133→            queryClient.invalidateQueries({ queryKey: ['reflect', 'snapshot'] });
134→          } catch { /* skip malformed event */ }
135→        } else if (event.event === 'error') {
136→          try {
137→            const data = JSON.parse(event.data) as { error?: string };
138→            setGenerationProgress(`Error: ${data.error ?? 'Unknown error'}`);
139→          } catch { /* skip malformed event */ }
140→        }
141→      }
142→    } catch (err) {
143→      if (err instanceof Error && err.name === 'AbortError') return;
144→      setGenerationProgress(err instanceof Error ? err.message : 'Generation failed');
145→    } finally {
146→      setGenerating(false);
147→    }
148→  }, [range, selectedProject]);
149→
150→  const handleCopy = useCallback((text: string, key: string) => {
151→    navigator.clipboard.writeText(text);
152→    setCopiedKey(key);
153→    setTimeout(() => setCopiedKey(null), 2000);
154→  }, []);
155→
156→  if (isLoading) {
157→    return (
158→      <div className="space-y-6 p-4 lg:p-6">
159→        <Skeleton className="h-8 w-48" />
160→        <div className="grid gap-4 md:grid-cols-3">
161→          <Skeleton className="h-32" />
162→          <Skeleton className="h-32" />
163→          <Skeleton className="h-32" />
164→        </div>
165→        <Skeleton className="h-64" />
166→      </div>
167→    );
168→  }
169→
170→  if (isError) {
171→    return (
172→      <div className="p-4 lg:p-6">
173→        <ErrorCard message="Failed to load patterns data" onRetry={refetch} />
174→      </div>
175→    );
176→  }
177→
178→  const frictionData = (aggregation?.frictionCategories || []).slice(0, 10).map(fc => ({
179→    category: fc.category,
180→    count: fc.count,
181→    severity: Math.round(fc.avg_severity * 10) / 10,
182→    color: frictionBarColor(fc.avg_severity),
183→  }));
184→
185→  const outcomeData = Object.entries(aggregation?.outcomeDistribution || {}).map(([name, value]) => ({
186→    name,
187→    value,
188→  }));
189→
190→  const workflowData = Object.entries(aggregation?.workflowDistribution || {}).map(([name, value]) => ({
191→    name: name.replace(/-/g, ' '),
192→    value,
193→  }));
194→
195→  const characterData = Object.entries(aggregation?.characterDistribution || {}).map(([name, value]) => ({
196→    name: name.replace(/_/g, ' '),
197→    value,
198→  }));
199→
200→  const hasEnoughFacets = (aggregation?.totalSessions ?? 0) >= 20;
201→  const coverageRatio = aggregation && aggregation.totalAllSessions > 0
202→    ? aggregation.totalSessions / aggregation.totalAllSessions
203→    : 0;
204→
205→  const frictionWinsResult = reflectResults?.['friction-wins'] as Record<string, unknown> | undefined;
206→  const rulesSkillsResult = reflectResults?.['rules-skills'] as Record<string, unknown> | undefined;
207→  const workingStyleResult = reflectResults?.['working-style'] as Record<string, unknown> | undefined;
208→
209→  const tagline = workingStyleResult?.tagline as string | undefined;
210→  const narrative = workingStyleResult?.narrative as string | undefined;
211→
212→  return (
213→    <div className="space-y-6 p-4 lg:p-6">
214→      {/* Header */}
215→      <div className="flex flex-col gap-2 sm:flex-row sm:items-start sm:justify-between">
216→        <div>
217→          <h1 className="text-2xl font-bold">Patterns</h1>
218→          <p className="text-sm text-muted-foreground">
219→            Cross-session analysis — friction, wins, and working style
220→          </p>
221→          {/* Snapshot metadata line — shown near controls */}
222→          {snapshotData?.snapshot && reflectResults && (
223→            <p className="text-xs text-muted-foreground mt-1">
224→              Generated {formatRelativeDate(snapshotData.snapshot.generatedAt)}
225→              {' · '}
226→              {snapshotData.snapshot.windowStart
227→                ? `${formatShortDate(snapshotData.snapshot.windowStart)} – ${formatShortDate(snapshotData.snapshot.windowEnd)}`
228→                : 'All time'}
229→              {' · '}
230→              {snapshotData.snapshot.sessionCount} sessions
231→              {aggregation && aggregation.totalSessions > snapshotData.snapshot.sessionCount && (
232→                <> — <span className="text-amber-500">{aggregation.totalSessions - snapshotData.snapshot.sessionCount} new since</span></>
233→              )}
234→            </p>
235→          )}
236→        </div>
237→        <div className="flex items-center gap-2 flex-wrap">
238→          <div className="flex rounded-lg border bg-muted p-0.5">
239→            {rangeOptions.map(opt => (
240→              <Button
241→                key={opt.value}
242→                variant={range === opt.value ? 'default' : 'ghost'}
243→                size="sm"
244→                className="h-7 px-3 text-xs"
245→                onClick={() => handleRangeChange(opt.value)}
246→              >
247→                {opt.label}
248→              </Button>
249→            ))}
250→          </div>
251→          {projects.length > 1 && (
252→            <select
253→              value={selectedProject || ''}
254→              onChange={(e) => handleProjectChange(e.target.value || undefined)}
255→              className="h-8 rounded-md border bg-background px-2 text-xs"
256→            >
257→              <option value="">All Projects</option>
258→              {projects.map(p => (
259→                <option key={p.id} value={p.id}>{p.name}</option>
260→              ))}
261→            </select>
262→          )}
263→          <Button
264→            onClick={handleGenerate}
265→            disabled={generating || !hasEnoughFacets}
266→            size="sm"
267→          >
268→            {generating ? (
269→              <><Loader2 className="h-4 w-4 mr-1.5 animate-spin" />Generating...</>
270→            ) : reflectResults ? (
271→              <><Sparkles className="h-4 w-4 mr-1.5" />Regenerate</>
272→            ) : (
273→              <><Sparkles className="h-4 w-4 mr-1.5" />Generate</>
274→            )}
275→          </Button>
276→        </div>
277→      </div>
278→
279→      {/* Threshold gate */}
280→      {!hasEnoughFacets && aggregation && aggregation.totalAllSessions > 0 && (
281→        <div className="flex items-start gap-3 rounded-lg border border-muted bg-muted/30 p-4">
282→          <AlertTriangle className="h-5 w-5 text-muted-foreground mt-0.5 shrink-0" />
283→          <div>
284→            <p className="text-sm font-medium">
285→              Not enough analyzed sessions for pattern synthesis
286→            </p>
287→            <p className="text-xs text-muted-foreground mt-1">
288→              Need at least 20 sessions with facets (currently {aggregation.totalSessions}).
289→              Run session analysis to extract facets from more sessions.
290→            </p>
291→          </div>
292→        </div>
293→      )}
294→
295→      {/* Coverage warning */}
296→      {hasEnoughFacets && coverageRatio > 0 && coverageRatio < 0.5 && aggregation && (
297→        <div className="flex items-start gap-3 rounded-lg border border-amber-500/30 bg-amber-50 dark:bg-amber-950/20 p-4">
298→          <AlertTriangle className="h-5 w-5 text-amber-500 mt-0.5 shrink-0" />
299→          <div>
300→            <p className="text-sm font-medium">
301→              {aggregation.totalSessions} of {aggregation.totalAllSessions} sessions analyzed
302→            </p>
303→            <p className="text-xs text-muted-foreground mt-1">
304→              Results may not represent your full patterns. Analyze more sessions for better accuracy.
305→            </p>
306→          </div>
307→        </div>
308→      )}
309→
310→      {/* Generation progress */}
311→      {generating && (
312→        <Card>
313→          <CardContent className="py-4">
314→            <div className="flex items-center gap-3">
315→              <Loader2 className="h-4 w-4 animate-spin text-muted-foreground" />
316→              <span className="text-sm text-muted-foreground">{generationProgress}</span>
317→            </div>
318→          </CardContent>
319→        </Card>
320→      )}
321→
322→      {/* Hero card — always visible above tabs */}
323→      <WorkingStyleHeroCard
324→        tagline={tagline}
325→        sessionsAnalyzed={aggregation?.totalSessions ?? 0}
326→        streak={aggregation?.streak ?? 0}
327→        toolsUsed={aggregation?.sourceToolCount ?? 0}
328→        characterDistribution={aggregation?.characterDistribution ?? {}}
329→        hasGenerated={!!reflectResults}
330→      />
331→
332→      {/* 2-tab layout */}
333→      <Tabs defaultValue="insights">
334→        <TabsList variant="line" className="w-full justify-start border-b rounded-none px-0 h-auto pb-0">
335→          <TabsTrigger value="insights" className="flex items-center gap-1.5 pb-2.5">
336→            <Brain className="h-4 w-4" />
337→            Insights
338→          </TabsTrigger>
339→          <TabsTrigger value="artifacts" className="flex items-center gap-1.5 pb-2.5">
340→            <Shield className="h-4 w-4" />
341→            Artifacts
342→          </TabsTrigger>
343→        </TabsList>
344→
345→        {/* INSIGHTS TAB */}
346→        <TabsContent value="insights" className="mt-6 space-y-6">
347→          {/* Working style narrative */}
348→          {narrative && (
349→            <Card className="border-l-2 border-primary">
350→              <CardHeader>
351→                <CardTitle className="text-base">Working Style</CardTitle>
352→              </CardHeader>
353→              <CardContent>
354→                <p className="text-sm leading-relaxed whitespace-pre-wrap">{narrative}</p>
355→              </CardContent>
356→            </Card>
357→          )}
358→
359→          {/* Distribution pie charts */}
360→          {(outcomeData.length > 0 || workflowData.length > 0 || characterData.length > 0) && (
361→            <div className="grid gap-4 md:grid-cols-3">
362→              {outcomeData.length > 0 && (
363→                <Card>
364→                  <CardHeader className="pb-2">
365→                    <CardTitle className="text-base">Outcome Distribution</CardTitle>
366→                  </CardHeader>
367→                  <CardContent>
368→                    <ResponsiveContainer width="100%" height={180}>
369→                      <PieChart>
370→                        <Pie data={outcomeData} dataKey="value" nameKey="name" cx="50%" cy="50%" outerRadius={60} label>
371→                          {outcomeData.map((_, i) => (
372→                            <Cell key={i} fill={PALETTE[i % PALETTE.length]} />
373→                          ))}
374→                        </Pie>
375→                        <Tooltip contentStyle={{ background: tooltipBg, border: `1px solid ${tooltipBorder}`, borderRadius: 8 }} />
376→                        <Legend />
377→                      </PieChart>
378→                    </ResponsiveContainer>
379→                  </CardContent>
380→                </Card>
381→              )}
382→
383→              {workflowData.length > 0 && (
384→                <Card>
385→                  <CardHeader className="pb-2">
386→                    <CardTitle className="text-base">Workflow Patterns</CardTitle>
387→                  </CardHeader>
388→                  <CardContent>
389→                    <ResponsiveContainer width="100%" height={180}>
390→                      <PieChart>
391→                        <Pie data={workflowData} dataKey="value" nameKey="name" cx="50%" cy="50%" outerRadius={60} label>
392→                          {workflowData.map((_, i) => (
393→                            <Cell key={i} fill={PALETTE[(i + 2) % PALETTE.length]} />
394→                          ))}
395→                        </Pie>
396→                        <Tooltip contentStyle={{ background: tooltipBg, border: `1px solid ${tooltipBorder}`, borderRadius: 8 }} />
397→                        <Legend />
398→                      </PieChart>
399→                    </ResponsiveContainer>
400→                  </CardContent>
401→                </Card>
402→              )}
403→
404→              {characterData.length > 0 && (
405→                <Card>
406→                  <CardHeader className="pb-2">
407→                    <CardTitle className="text-base">Session Types</CardTitle>
408→                  </CardHeader>
409→                  <CardContent>
410→                    <ResponsiveContainer width="100%" height={180}>
411→                      <PieChart>
412→                        <Pie data={characterData} dataKey="value" nameKey="name" cx="50%" cy="50%" outerRadius={60} label>
413→                          {characterData.map((_, i) => (
414→                            <Cell key={i} fill={PALETTE[(i + 4) % PALETTE.length]} />
415→                          ))}
416→                        </Pie>
417→                        <Tooltip contentStyle={{ background: tooltipBg, border: `1px solid ${tooltipBorder}`, borderRadius: 8 }} />
418→                        <Legend />
419→                      </PieChart>
420→                    </ResponsiveContainer>
421→                  </CardContent>
422→                </Card>
423→              )}
424→            </div>
425→          )}
426→
427→          {/* Friction narrative */}
428→          {frictionWinsResult?.narrative && (
429→            <Card className="border-l-2 border-primary">
430→              <CardHeader>
431→                <CardTitle className="text-base">Friction Analysis</CardTitle>
432→              </CardHeader>
433→              <CardContent>
434→                <p className="text-sm leading-relaxed whitespace-pre-wrap">
435→                  {String(frictionWinsResult.narrative)}
436→                </p>
437→              </CardContent>
438→            </Card>
439→          )}
440→
441→          {/* Friction bar chart — severity-colored bars */}
442→          {frictionData.length > 0 ? (
443→            <Card>
444→              <CardHeader>
445→                <CardTitle className="text-base">Friction Categories</CardTitle>
446→                <CardDescription>Most common blockers across sessions — color indicates severity</CardDescription>
447→              </CardHeader>
448→              <CardContent>
449→                <ResponsiveContainer width="100%" height={Math.max(200, frictionData.length * 36)}>
450→                  <BarChart data={frictionData} layout="vertical" margin={{ left: 120 }}>
451→                    <CartesianGrid strokeDasharray="3 3" stroke="var(--color-border)" />
452→                    <XAxis type="number" />
453→                    <YAxis type="category" dataKey="category" width={110} tick={{ fontSize: 12 }} />
454→                    <Tooltip
455→                      contentStyle={{ background: tooltipBg, border: `1px solid ${tooltipBorder}`, borderRadius: 8 }}
456→                    />
457→                    <Bar dataKey="count" radius={[0, 4, 4, 0]}>
458→                      {frictionData.map((entry, i) => (
459→                        <Cell key={i} fill={entry.color} />
460→                      ))}
461→                    </Bar>
462→                  </BarChart>
463→                </ResponsiveContainer>
464→              </CardContent>
465→            </Card>
466→          ) : (
467→            <Card>
468→              <CardContent className="py-8 text-center text-muted-foreground">
469→                No friction data yet. Analyze sessions to extract facets.
470→              </CardContent>
471→            </Card>
472→          )}
473→
474→          {/* Rate limit usage insight */}
475→          {aggregation?.rateLimitInfo && aggregation.rateLimitInfo.count > 0 && (
476→            <div className="flex items-start gap-3 rounded-lg border border-amber-500/30 bg-amber-50 dark:bg-amber-950/20 p-4">
477→              <Zap className="h-5 w-5 text-amber-500 mt-0.5 shrink-0" />
478→              <div>
479→                <p className="text-sm font-medium text-amber-800 dark:text-amber-200">
480→                  Usage Insight: API Rate Limits
481→                </p>
482→                <p className="text-xs text-amber-700 dark:text-amber-300 mt-1">
483→                  You hit API rate limits {aggregation.rateLimitInfo.count} time{aggregation.rateLimitInfo.count !== 1 ? 's' : ''} in the last {range} ({aggregation.rateLimitInfo.sessionsAffected} session{aggregation.rateLimitInfo.sessionsAffected !== 1 ? 's' : ''} affected). Consider upgrading your subscription or checking your API rate limits — your usage may exceed your current plan's token or request limits.
484→                </p>
485→              </div>
486→            </div>
487→          )}
488→
489→          {/* Effective patterns — styled frequency badges */}
490→          {(aggregation?.effectivePatterns || []).length > 0 && (
491→            <Card>
492→              <CardHeader>
493→                <CardTitle className="text-base">Effective Patterns</CardTitle>
494→                <CardDescription>Techniques that work well across sessions</CardDescription>
495→              </CardHeader>
496→              <CardContent>
497→                <ul className="divide-y">
498→                  {aggregation!.effectivePatterns.slice(0, 8).map((ep, i) => (
499→                    <li key={i} className="flex items-start gap-3 py-3 first:pt-0 last:pb-0">
500→                      <span className="inline-flex items-center rounded px-1.5 py-0.5 text-xs font-semibold bg-primary/10 text-primary shrink-0 mt-0.5">
501→                        {ep.frequency}x
502→                      </span>
503→                      <span className="text-sm">{ep.description}</span>
504→                    </li>
505→                  ))}
506→                </ul>
507→              </CardContent>
508→            </Card>
509→          )}
510→        </TabsContent>
511→
512→        {/* ARTIFACTS TAB */}
513→        <TabsContent value="artifacts" className="mt-6 space-y-6">
514→          {rulesSkillsResult ? (
515→            <>
516→              {/* CLAUDE.md Rules */}
517→              {Array.isArray(rulesSkillsResult.claudeMdRules) && (rulesSkillsResult.claudeMdRules as Array<{ rule: string; rationale: string; frictionSource: string }>).length > 0 && (
518→                <Card className="border-l-2 border-primary">
519→                  <CardHeader>
520→                    <CardTitle className="text-base">CLAUDE.md Rules</CardTitle>
521→                    <CardDescription>Add these to your AI assistant configuration</CardDescription>
522→                  </CardHeader>
523→                  <CardContent className="space-y-3">
524→                    {(rulesSkillsResult.claudeMdRules as Array<{ rule: string; rationale: string; frictionSource: string }>).map((r, i) => (
525→                      <div key={i} className="rounded-lg border p-3">
526→                        <div className="flex items-start justify-between gap-2">
527→                          <code className="text-sm font-mono flex-1">{r.rule}</code>
528→                          <Button
529→                            variant="ghost"
530→                            size="icon"
531→                            className="h-8 w-8 shrink-0"
532→                            onClick={() => handleCopy(r.rule, `rule-${i}`)}
533→                          >
