300→export async function backfillFacets(sessionIds: string[]): Promise<{ completed: number; failed: number }> {
301→  // The /api/facets/backfill endpoint returns an SSE stream, not JSON.
302→  // Using raw fetch here instead of request() which calls res.json() and would crash.
303→  const res = await fetch(`${BASE}/facets/backfill`, {
304→    method: 'POST',
305→    headers: { 'Content-Type': 'application/json' },
306→    body: JSON.stringify({ sessionIds }),
307→  });
308→  if (!res.ok) {
309→    const text = await res.text().catch(() => res.statusText);
310→    throw new Error(`API ${res.status}: ${text}`);
311→  }
312→  if (!res.body) throw new Error('No response body');
313→
314→  const reader = res.body.pipeThrough(new TextDecoderStream()).getReader();
315→  let buffer = '';
316→  let currentEvent = '';
317→  let currentData = '';
318→  let result = { completed: 0, failed: 0 };
319→
320→  try {
321→    while (true) {
322→      const { done, value } = await reader.read();
323→      if (done) break;
324→      buffer += value;
325→      const lines = buffer.split('\n');
326→      buffer = lines.pop() ?? '';
327→      for (const line of lines) {
328→        if (line.startsWith('event: ')) {
329→          currentEvent = line.slice(7).trim();
330→        } else if (line.startsWith('data: ')) {
331→          currentData = line.slice(6);
332→        } else if (line === '' && currentEvent && currentData) {
333→          if (currentEvent === 'complete') {
334→            const data = JSON.parse(currentData) as { completed: number; failed: number };
335→            result = { completed: data.completed, failed: data.failed };
336→          }
337→          currentEvent = '';
338→          currentData = '';
339→        }
340→      }
341→    }
342→  } finally {
343→    reader.releaseLock();
344→  }
345→
346→  return result;
347→}
