 6→
 7→/**
 8→ * Parse SSE events from a ReadableStream response body.
 9→ * Handles partial chunks by buffering lines until a complete event is received.
10→ */
11→export async function* parseSSEStream(
12→  body: ReadableStream<Uint8Array>
13→): AsyncGenerator<{ event: string; data: string }> {
14→  const reader = body.pipeThrough(new TextDecoderStream()).getReader();
15→  let buffer = '';
16→  let currentEvent = '';
17→  let currentData = '';
18→
19→  try {
20→    while (true) {
21→      const { done, value } = await reader.read();
22→      if (done) break;
23→
24→      buffer += value;
25→      const lines = buffer.split('\n');
26→      // Keep the last potentially incomplete line in the buffer
27→      buffer = lines.pop() ?? '';
28→
29→      for (const line of lines) {
30→        if (line.startsWith('event: ')) {
31→          currentEvent = line.slice(7).trim();
32→        } else if (line.startsWith('data: ')) {
33→          currentData = line.slice(6);
34→        } else if (line === '' && currentEvent && currentData) {
35→          yield { event: currentEvent, data: currentData };
36→          currentEvent = '';
37→          currentData = '';
38→        }
39→      }
40→    }
41→    // Flush any remaining buffered event
42→    if (currentEvent && currentData) {
43→      yield { event: currentEvent, data: currentData };
44→    }
45→  } finally {
46→    reader.releaseLock();
47→  }
