 35→function formatRelativeDate(iso: string): string {
 36→  const diff = Date.now() - new Date(iso).getTime();
 37→  const mins = Math.max(0, Math.floor(diff / 60000));
 38→  if (mins < 1) return 'just now';
 39→  if (mins < 60) return `${mins}m ago`;
 40→  const hours = Math.floor(mins / 60);
 41→  if (hours < 24) return `${hours}h ago`;
 42→  const days = Math.floor(hours / 24);
 43→  return `${days}d ago`;
 44→}
 45→
 46→function formatShortDate(iso: string): string {
 47→  return new Date(iso).toLocaleDateString('en-US', { month: 'short', day: 'numeric' });
 48→}
 49→
 50→type PatternsRange = '7d' | '30d' | '90d' | 'all';
 51→
 52→const rangeOptions: { value: PatternsRange; label: string }[] = [
 53→  { value: '7d', label: '7d' },
 54→  { value: '30d', label: '30d' },
 55→  { value: '90d', label: '90d' },
 56→  { value: 'all', label: 'All' },
 57→];
 58→
 59→export default function PatternsPage() {
 60→  const [range, setRange] = useState<PatternsRange>('30d');
 61→  const [selectedProject, setSelectedProject] = useState<string | undefined>(undefined);
 62→  const [generating, setGenerating] = useState(false);
 63→  const [generationProgress, setGenerationProgress] = useState('');
 64→  const [reflectResults, setReflectResults] = useState<Record<string, unknown> | null>(null);
 65→  const [copiedKey, setCopiedKey] = useState<string | null>(null);
 66→  const { tooltipBg, tooltipBorder } = useThemeColors();
 67→  const abortRef = useRef<AbortController | null>(null);
 68→  const queryClient = useQueryClient();
 69→
 70→  const { data: projects = [] } = useProjects();
 71→
 72→  const { data: snapshotData } = useReflectSnapshot({
 73→    period: range,
 74→    project: selectedProject,
 75→  });
 76→
 77→  const { data: aggregation, isLoading, isError, refetch } = useFacetAggregation({
 78→    period: range,
 79→    project: selectedProject,
 80→  });
 81→
 82→  // Abort in-flight generation on unmount
 83→  useEffect(() => {
 84→    return () => {
 85→      abortRef.current?.abort();
 86→    };
 87→  }, []);
 88→
 89→  // Auto-load cached snapshot when it arrives and no local results exist yet
 90→  useEffect(() => {
 91→    if (snapshotData?.snapshot?.results && !reflectResults && !generating) {
 92→      setReflectResults(snapshotData.snapshot.results);
 93→    }
 94→  }, [snapshotData, reflectResults, generating]);
 95→
 96→  const handleRangeChange = useCallback((newRange: PatternsRange) => {
 97→    setRange(newRange);
 98→    setReflectResults(null);
 99→  }, []);
100→
101→  const handleProjectChange = useCallback((projectId: string | undefined) => {
102→    setSelectedProject(projectId);
103→    setReflectResults(null);
104→  }, []);
105→
106→  const handleGenerate = useCallback(async () => {
107→    abortRef.current?.abort();
108→    const controller = new AbortController();
109→    abortRef.current = controller;
110→
111→    setGenerating(true);
112→    setGenerationProgress('Starting...');
113→    setReflectResults(null);
114→
115→    try {
116→      const response = await reflectGenerateStream(
117→        { period: range, project: selectedProject },
118→        controller.signal
119→      );
120→
121→      if (!response.body) throw new Error('No response body');
122→
123→      for await (const event of parseSSEStream(response.body)) {
124→        if (event.event === 'progress') {
125→          try {
126→            const data = JSON.parse(event.data) as { message?: string };
127→            setGenerationProgress(data.message || 'Processing...');
128→          } catch { /* skip malformed event */ }
129→        } else if (event.event === 'complete') {
130→          try {
131→            const data = JSON.parse(event.data) as { results?: Record<string, unknown> };
132→            setReflectResults(data.results ?? null);
133→            queryClient.invalidateQueries({ queryKey: ['reflect', 'snapshot'] });
134→          } catch { /* skip malformed event */ }
135→        } else if (event.event === 'error') {
136→          try {
137→            const data = JSON.parse(event.data) as { error?: string };
138→            setGenerationProgress(`Error: ${data.error ?? 'Unknown error'}`);
139→          } catch { /* skip malformed event */ }
140→        }
141→      }
142→    } catch (err) {
143→      if (err instanceof Error && err.name === 'AbortError') return;
144→      setGenerationProgress(err instanceof Error ? err.message : 'Generation failed');
145→    } finally {
146→      setGenerating(false);
147→    }
148→  }, [range, selectedProject]);
149→
150→  const handleCopy = useCallback((text: string, key: string) => {
151→    navigator.clipboard.writeText(text);
152→    setCopiedKey(key);
153→    setTimeout(() => setCopiedKey(null), 2000);
154→  }, []);
155→
156→  if (isLoading) {
157→    return (
158→      <div className="space-y-6 p-4 lg:p-6">
159→        <Skeleton className="h-8 w-48" />
160→        <div className="grid gap-4 md:grid-cols-3">
161→          <Skeleton className="h-32" />
162→          <Skeleton className="h-32" />
163→          <Skeleton className="h-32" />
164→        </div>
165→        <Skeleton className="h-64" />
166→      </div>
167→    );
168→  }
169→
170→  if (isError) {
171→    return (
172→      <div className="p-4 lg:p-6">
173→        <ErrorCard message="Failed to load patterns data" onRetry={refetch} />
174→      </div>
175→    );
176→  }
177→
178→  const frictionData = (aggregation?.frictionCategories || []).slice(0, 10).map(fc => ({
179→    category: fc.category,
180→    count: fc.count,
181→    severity: Math.round(fc.avg_severity * 10) / 10,
182→    color: frictionBarColor(fc.avg_severity),
183→  }));
184→
185→  const outcomeData = Object.entries(aggregation?.outcomeDistribution || {}).map(([name, value]) => ({
186→    name,
187→    value,
188→  }));
189→
190→  const workflowData = Object.entries(aggregation?.workflowDistribution || {}).map(([name, value]) => ({
191→    name: name.replace(/-/g, ' '),
192→    value,
193→  }));
194→
195→  const characterData = Object.entries(aggregation?.characterDistribution || {}).map(([name, value]) => ({
196→    name: name.replace(/_/g, ' '),
197→    value,
198→  }));
199→
200→  const hasEnoughFacets = (aggregation?.totalSessions ?? 0) >= 20;
201→  const coverageRatio = aggregation && aggregation.totalAllSessions > 0
202→    ? aggregation.totalSessions / aggregation.totalAllSessions
203→    : 0;
204→
205→  const frictionWinsResult = reflectResults?.['friction-wins'] as Record<string, unknown> | undefined;
206→  const rulesSkillsResult = reflectResults?.['rules-skills'] as Record<string, unknown> | undefined;
207→  const workingStyleResult = reflectResults?.['working-style'] as Record<string, unknown> | undefined;
208→
209→  const tagline = workingStyleResult?.tagline as string | undefined;
210→  const narrative = workingStyleResult?.narrative as string | undefined;
211→
212→  return (
213→    <div className="space-y-6 p-4 lg:p-6">
214→      {/* Header */}
215→      <div className="flex flex-col gap-2 sm:flex-row sm:items-start sm:justify-between">
216→        <div>
217→          <h1 className="text-2xl font-bold">Patterns</h1>
218→          <p className="text-sm text-muted-foreground">
219→            Cross-session analysis — friction, wins, and working style
220→          </p>
221→          {/* Snapshot metadata line — shown near controls */}
222→          {snapshotData?.snapshot && reflectResults && (
223→            <p className="text-xs text-muted-foreground mt-1">
224→              Generated {formatRelativeDate(snapshotData.snapshot.generatedAt)}
225→              {' · '}
226→              {snapshotData.snapshot.windowStart
227→                ? `${formatShortDate(snapshotData.snapshot.windowStart)} – ${formatShortDate(snapshotData.snapshot.windowEnd)}`
228→                : 'All time'}
229→              {' · '}
230→              {snapshotData.snapshot.sessionCount} sessions
231→              {aggregation && aggregation.totalSessions > snapshotData.snapshot.sessionCount && (
232→                <> — <span className="text-amber-500">{aggregation.totalSessions - snapshotData.snapshot.sessionCount} new since</span></>
233→              )}
234→            </p>
235→          )}
236→        </div>
237→        <div className="flex items-center gap-2 flex-wrap">
238→          <div className="flex rounded-lg border bg-muted p-0.5">
239→            {rangeOptions.map(opt => (
240→              <Button
241→                key={opt.value}
242→                variant={range === opt.value ? 'default' : 'ghost'}
243→                size="sm"
244→                className="h-7 px-3 text-xs"
245→                onClick={() => handleRangeChange(opt.value)}
246→              >
247→                {opt.label}
248→              </Button>
249→            ))}
250→          </div>
251→          {projects.length > 1 && (
252→            <select
253→              value={selectedProject || ''}
254→              onChange={(e) => handleProjectChange(e.target.value || undefined)}
255→              className="h-8 rounded-md border bg-background px-2 text-xs"
256→            >
257→              <option value="">All Projects</option>
258→              {projects.map(p => (
259→                <option key={p.id} value={p.id}>{p.name}</option>
260→              ))}
261→            </select>
262→          )}
263→          <Button
264→            onClick={handleGenerate}
265→            disabled={generating || !hasEnoughFacets}
266→            size="sm"
267→          >
268→            {generating ? (
269→              <><Loader2 className="h-4 w-4 mr-1.5 animate-spin" />Generating...</>
270→            ) : reflectResults ? (
271→              <><Sparkles className="h-4 w-4 mr-1.5" />Regenerate</>
272→            ) : (
273→              <><Sparkles className="h-4 w-4 mr-1.5" />Generate</>
274→            )}
275→          </Button>
276→        </div>
277→      </div>
278→
279→      {/* Threshold gate */}
280→      {!hasEnoughFacets && aggregation && aggregation.totalAllSessions > 0 && (
281→        <div className="flex items-start gap-3 rounded-lg border border-muted bg-muted/30 p-4">
282→          <AlertTriangle className="h-5 w-5 text-muted-foreground mt-0.5 shrink-0" />
283→          <div>
284→            <p className="text-sm font-medium">
285→              Not enough analyzed sessions for pattern synthesis
286→            </p>
287→            <p className="text-xs text-muted-foreground mt-1">
