598→                            {fc.category}
599→                          </li>
600→                        ))}
601→                      </ul>
602→                    </div>
603→                  )}
604→                  {aggregation.effectivePatterns.filter(ep => ep.frequency >= 2).length > 0 && (
605→                    <div>
606→                      <p className="text-xs font-medium text-muted-foreground mb-2">Effective patterns (2+ occurrences):</p>
607→                      <ul className="space-y-1">
608→                        {aggregation.effectivePatterns.filter(ep => ep.frequency >= 2).map((ep, i) => (
609→                          <li key={i} className="text-sm flex items-center gap-2">
610→                            <span className="text-xs font-mono text-muted-foreground">{ep.frequency}x</span>
611→                            {ep.description}
612→                          </li>
613→                        ))}
614→                      </ul>
615→                    </div>
616→                  )}
617→                  {aggregation.frictionCategories.filter(fc => fc.count >= 3).length === 0 &&
618→                   aggregation.effectivePatterns.filter(ep => ep.frequency >= 2).length === 0 && (
619→                    <p className="text-sm text-muted-foreground">
620→                      No recurring patterns yet. Analyze more sessions to detect patterns.
621→                    </p>
622→                  )}
623→                </CardContent>
624→              </Card>
625→            )
626→          )}
627→        </TabsContent>
628→      </Tabs>
629→    </div>
630→  );
631→}
