  1→import { Brain } from 'lucide-react';
  2→
  3→// Color palette for donut segments — matches the page's existing PALETTE
  4→const DONUT_COLORS = ['#6366f1', '#8b5cf6', '#a78bfa', '#c4b5fd'];
  5→
  6→interface DonutSegment {
  7→  label: string;
  8→  value: number;
  9→  color: string;
 10→}
 11→
 12→function buildDonutSegments(characterDistribution: Record<string, number>): DonutSegment[] {
 13→  const entries = Object.entries(characterDistribution).sort((a, b) => b[1] - a[1]);
 14→  const total = entries.reduce((sum, [, v]) => sum + v, 0);
 15→  if (total === 0) return [];
 16→
 17→  // Top 3 by count, rest grouped as "other"
 18→  const top = entries.slice(0, 3);
 19→  const otherTotal = entries.slice(3).reduce((sum, [, v]) => sum + v, 0);
 20→
 21→  const segments: DonutSegment[] = top.map(([label, value], i) => ({
 22→    label: label.replace(/_/g, ' '),
 23→    value,
 24→    color: DONUT_COLORS[i],
 25→  }));
 26→
 27→  if (otherTotal > 0) {
 28→    segments.push({ label: 'other', value: otherTotal, color: DONUT_COLORS[3] });
 29→  }
 30→
 31→  return segments;
 32→}
 33→
 34→function DonutChart({ segments }: { segments: DonutSegment[] }) {
 35→  const cx = 60;
 36→  const cy = 60;
 37→  const outerR = 52;
 38→  const innerR = 34;
 39→
 40→  const total = segments.reduce((sum, s) => sum + s.value, 0);
 41→  if (total === 0) {
 42→    return (
 43→      <svg width="120" height="120" viewBox="0 0 120 120" role="img" aria-label="Session type distribution: no data">
 44→        <circle cx={cx} cy={cy} r={outerR} fill="none" stroke="#ffffff20" strokeWidth={outerR - innerR} />
 45→      </svg>
 46→    );
 47→  }
 48→
 49→  let currentAngle = -Math.PI / 2; // Start at top (12 o'clock)
 50→  const paths: Array<{ d: string; color: string }> = [];
 51→
 52→  for (const segment of segments) {
 53→    const fraction = segment.value / total;
 54→    // Clamp to just under full circle to avoid degenerate arc (point to point)
 55→    const sweepAngle = Math.min(fraction * 2 * Math.PI, 2 * Math.PI - 0.001);
 56→
 57→    const x1 = cx + outerR * Math.cos(currentAngle);
 58→    const y1 = cy + outerR * Math.sin(currentAngle);
 59→    const x2 = cx + outerR * Math.cos(currentAngle + sweepAngle);
 60→    const y2 = cy + outerR * Math.sin(currentAngle + sweepAngle);
 61→    const ix1 = cx + innerR * Math.cos(currentAngle + sweepAngle);
 62→    const iy1 = cy + innerR * Math.sin(currentAngle + sweepAngle);
 63→    const ix2 = cx + innerR * Math.cos(currentAngle);
 64→    const iy2 = cy + innerR * Math.sin(currentAngle);
 65→    const largeArc = sweepAngle > Math.PI ? 1 : 0;
 66→
 67→    const d = [
 68→      `M ${x1} ${y1}`,
 69→      `A ${outerR} ${outerR} 0 ${largeArc} 1 ${x2} ${y2}`,
 70→      `L ${ix1} ${iy1}`,
 71→      `A ${innerR} ${innerR} 0 ${largeArc} 0 ${ix2} ${iy2}`,
 72→      'Z',
 73→    ].join(' ');
 74→
 75→    paths.push({ d, color: segment.color });
 76→    currentAngle += sweepAngle;
 77→  }
 78→
 79→  const ariaLabel = 'Session type distribution: ' + segments
 80→    .map(s => `${s.label} ${Math.round((s.value / total) * 100)}%`)
 81→    .join(', ');
 82→
 83→  return (
 84→    <svg width="120" height="120" viewBox="0 0 120 120" role="img" aria-label={ariaLabel}>
 85→      {paths.map((p) => (
 86→        <path key={p.color} d={p.d} fill={p.color} opacity={0.9} />
 87→      ))}
 88→    </svg>
 89→  );
 90→}
 91→
 92→const MAX_TAGLINE_CHARS = 40;
 93→
 94→interface WorkingStyleHeroCardProps {
 95→  tagline?: string;
 96→  sessionsAnalyzed: number;
 97→  streak: number;
 98→  toolsUsed: number;
 99→  characterDistribution: Record<string, number>;
100→  hasGenerated: boolean;
101→}
102→
103→export function WorkingStyleHeroCard({
104→  tagline,
105→  sessionsAnalyzed,
106→  streak,
107→  toolsUsed,
108→  characterDistribution,
109→  hasGenerated,
110→}: WorkingStyleHeroCardProps) {
111→  const segments = buildDonutSegments(characterDistribution);
112→
113→  return (
114→    <div
115→      className="relative overflow-hidden rounded-xl p-6"
116→      style={{ background: 'linear-gradient(135deg, #0f0f23, #1a1a3e)' }}
117→    >
118→      {/* Branding */}
119→      <div className="flex items-center gap-1.5 mb-4">
120→        <Brain className="h-3.5 w-3.5 text-blue-400" />
121→        <span className="text-[10px] font-semibold tracking-widest text-blue-400/80 uppercase">
122→          Code Insights
123→        </span>
124→      </div>
125→
126→      <div className="flex items-center justify-between gap-4">
127→        <div className="flex-1 min-w-0">
128→          {/* Tagline */}
129→          {hasGenerated && tagline ? (
130→            <h2
131→              className="text-2xl font-bold mb-3 leading-tight"
132→              style={{
133→                background: 'linear-gradient(to right, #60a5fa, #c084fc)',
134→                WebkitBackgroundClip: 'text',
135→                WebkitTextFillColor: 'transparent',
136→                backgroundClip: 'text',
137→              }}
138→            >
139→              {tagline.length > MAX_TAGLINE_CHARS ? tagline.slice(0, MAX_TAGLINE_CHARS - 1) + '…' : tagline}
140→            </h2>
141→          ) : (
142→            <p className="text-sm text-white/50 mb-3 italic">
143→              Generate patterns to discover your working style
144→            </p>
145→          )}
146→
147→          {/* Stat pills */}
148→          <div className="flex flex-wrap gap-2">
149→            <StatPill label="Sessions analyzed" value={sessionsAnalyzed} />
150→            <StatPill label="Active streak" value={streak} unit="d" />
151→            <StatPill label="AI tools" value={toolsUsed} />
152→          </div>
153→        </div>
154→
155→        {/* Donut chart */}
156→        <div className="shrink-0 opacity-90">
157→          <DonutChart segments={segments} />
158→        </div>
159→      </div>
160→    </div>
161→  );
162→}
163→
164→function StatPill({
165→  label,
166→  value,
167→  unit,
168→}: {
169→  label: string;
170→  value: number;
171→  unit?: string;
172→}) {
173→  return (
174→    <div className="rounded-full bg-white/10 px-3 py-1 text-xs text-white/80 flex items-center gap-1">
175→      <span className="font-semibold text-white">
176→        {value}{unit}
177→      </span>
178→      <span className="text-white/50">{label}</span>
179→    </div>
180→  );
181→}
